local function validate_token(token)
    if not token or token == "" then
        return nil, "Missing token"
    end
    
    if string.len(token) < 20 then
        return nil, "Invalid token format"
    end
    
    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        table.insert(parts, part)
    end
    
    if #parts ~= 3 then
        return nil, "Invalid token structure"
    end
    
    return true
end

local function decode_base64(str)
    local b64chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    str = string.gsub(str, '[^'..b64chars..'=]', '')
    return (str:gsub('.', function(x)
        if x == '=' then return '' end
        local r, f = '', (b64chars:find(x) - 1)
        for i = 6, 1, -1 do
            r = r .. (f % 2^i - f % 2^(i-1) > 0 and '1' or '0')
        end
        return r
    end):gsub('%d%d%d?%d?%d?%d?%d?%d?', function(x)
        if #x ~= 8 then return '' end
        local c = 0
        for i = 1, 8 do
            c = c + (x:sub(i, i) == '1' and 2^(8-i) or 0)
        end
        return string.char(c)
    end))
end

local function extract_user_info(token)
    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        table.insert(parts, part)
    end
    
    if #parts < 2 then
        return nil
    end
    
    local payload = parts[2]
    payload = payload:gsub('-', '+'):gsub('_', '/')
    local padding = #payload % 4
    if padding > 0 then
        payload = payload .. string.rep('=', 4 - padding)
    end
    
    local decoded = decode_base64(payload)
    
    local user_info = {}
    local role_match = string.match(decoded, '"role"%s*:%s*"([^"]+)"')
    local user_match = string.match(decoded, '"user"%s*:%s*"([^"]+)"')
    local username_match = string.match(decoded, '"username"%s*:%s*"([^"]+)"')
    local userid_match = string.match(decoded, '"user_id"%s*:%s*"([^"]+)"')
    
    user_info.role = role_match
    user_info.user = user_match or username_match
    user_info.user_id = userid_match
    
    return user_info
end

local function check_role_permission(user_role, required_role)
    if not user_role or not required_role then
        return false
    end
    
    local role_hierarchy = {
        admin = 3,
        moderator = 2,
        user = 1,
        guest = 0
    }
    
    local user_level = role_hierarchy[string.lower(user_role)] or 0
    local required_level = role_hierarchy[string.lower(required_role)] or 0
    
    return user_level >= required_level
end

local function should_skip_check(uri)
    if string.find(uri, "/admin") then
        return true
    end
    
    if string.find(uri, "/api") then
        return true
    end
    
    return false
end

local uri = ngx.var.uri

if should_skip_check(uri) then
    return
end

local auth_header = ngx.var.http_authorization

if not auth_header then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header["Content-Type"] = "application/json"
    ngx.say('{"error":"Authorization header missing"}')
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local token = string.match(auth_header, "Bearer%s+(.+)")

if not token then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header["Content-Type"] = "application/json"
    ngx.say('{"error":"Invalid authorization format"}')
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local valid, err = validate_token(token)
if not valid then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header["Content-Type"] = "application/json"
    ngx.say('{"error":"' .. err .. '"}')
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local user_info = extract_user_info(token)

if not user_info or not user_info.role then
    ngx.status = ngx.HTTP_UNAUTHORIZED
    ngx.header["Content-Type"] = "application/json"
    ngx.say('{"error":"Unable to extract user information"}')
    return ngx.exit(ngx.HTTP_UNAUTHORIZED)
end

local required_role = "user"

if string.find(uri, "/protected") then
    required_role = "moderator"
end

if not check_role_permission(user_info.role, required_role) then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.header["Content-Type"] = "application/json"
    ngx.say('{"error":"Insufficient permissions"}')
    return ngx.exit(ngx.HTTP_FORBIDDEN)
end

ngx.req.set_header("X-User-Role", user_info.role)
if user_info.user then
    ngx.req.set_header("X-User-Name", user_info.user)
end
if user_info.user_id then
    ngx.req.set_header("X-User-ID", user_info.user_id)
end